window.__QUIZ_DATA__=[{"id":"objective>Physics>1997>1","subject":"Physics","year":"1997","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"An object of mass 0.40 kg attached to the end of a string is whirled round in a horizontal circle of radius 2.0 m with a constant speed of 8 ms-1. Calculate the angular velocity of the object","images":[],"options":{"A":"0.8 rads-1","B":"2.0 rads-1","C":"4.0 rads-1","D":"8.0 rads-1"},"answer":"C","explanation":"v = \u03c9r; v = 8 ms-1; r = 2.0 m; \u03c9 = ?  \u03c9=vr=82=4.0rads-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>2","subject":"Physics","year":"1997","type":"Objective","topic":"RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY","question":"An object falls freely from a height of 25 m unto the roof a building of 5 m high. Calculate the velocity with which the object strikes the roof.  [g = 10 ms-2]","images":[],"options":{"A":"17.3 ms-1","B":"20.0 ms-1","C":"24.5 ms-1","D":"125.0 ms-1"},"answer":"B","explanation":"h = 25 m; height of building = 5 m; H = 25 - 5 = 20 m; u = 0; g = 10 ms-2; v = ?  v2 = u2 + 2gh  v2 = 2 x 10 x 20  v2 = 400  v = \u221a400  \u2234 v = 20.0 ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>3","subject":"Physics","year":"1997","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A body of mass 20 kg is set in motion by two forces 3 N and 4 N, acting at right angles to each other. Determine its magnitude of acceleration","images":[],"options":{"A":"400 ms-2","B":"2.89 ms-2","C":"0.35 ms-2","D":"0.25 ms-2"},"answer":"D","explanation":"m = 20 kg  |FR|2 = 32 + 42 = 9 + 16  |FR|2 = 25  |FR| = 5 N  F = ma; 5 = 20a  a=520=0.25ms-2","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>4","subject":"Physics","year":"1997","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 0.1 kg approaching a tennis player with a velocity of 10 ms-1, is hit back in the opposite direction with a velocity of 15 ms-1. If the time of impact between the racket and the ball is 0.01 s, calculate the magnitude of force with which the ball is hit.","images":[],"options":{"A":"5000 N","B":"500 N","C":"250 N","D":"50 N"},"answer":"C","explanation":"m = 0.1 kg; u = -10 ms-1; v = 15 ms-1; t = 0.01s; F = ?  impulse = Ft = m(v - u)  F x 0.01 = 0.1(15 - (-10))  F x 0.01 = 0.1(15 + 10)  0.01F = 0.1 x 25 = 2.5  F=2.50.01=250N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>5","subject":"Physics","year":"1997","type":"Objective","topic":"MOTION : MOTION UNDER GRAVITY","question":"Two blocks of the same dimensions, one steel and the other wooden are dropped simultaneously from the same height. If they fall freely, neglecting air resistance, the","images":[],"options":{"A":"two blocks hit the ground simultaneously because they have the same acceleration.","B":"two blocks reach the ground at the same time because their dimensions are the same.","C":"wooden block, being lighter than the steel block, reaches the ground first.","D":"steel block reaches the ground first because it is denser than the wooden block."},"answer":"A","explanation":"Because Earth gives everything the exact same acceleration, objects with different masses will still hit the ground at the same time if they are dropped from the same height.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>6","subject":"Physics","year":"1997","type":"Objective","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"Two forces 3 N and 4 N act on a body in directions due north and due east respectively. Calculate their equilibrant.","images":[],"options":{"A":"5 N, 53o east of north","B":"5 N, 53o west of south","C":"5 N, 37o north of east","D":"7 N, 37o west of north"},"answer":"C","explanation":"Y2 = 42 + 32; Y2 = 16 + 9 = 25;    Y = \u221a25 = 5    tan \u03b8 = 3/4    \u03b8 = tan-1 3/4 = 37o    5 N, 37o north of east    since 4 N is the greater force ==> it will push towards east.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>7","subject":"Physics","year":"1997","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"A missile weighing 400 N on the earth's surface is shot into the atmosphere to an altitude of 6.40 x 106 m. Taking the earth as a sphere of radius 6 x 106 m and assuming the inverse-square law of universal gravitation, what would be the weight of the missile at the altitude?","images":[],"options":{"A":"100 N","B":"200 N","C":"400 N","D":"800 N"},"answer":"A","explanation":"Fe=400N;M=massofearth;h=6.40x106m;m=massofmissile;r=6.40x106m  G=universalgravitationconstant  Fe=GMmr2==>G=Fer2Mm  atanaltitudeofh=6.40x106m  R=r+h=6.40x106+6.40x106=12.80x106m  F=GMmR2=Fer2MmxMmR2  F=Fer2R2=400 x (6.40 x 106)2(12.80 x 106)2  =400 x 6.402 x 101212.802 x 1012=400 x 6.40212.802  =16384163.38=100N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>8","subject":"Physics","year":"1997","type":"Objective","topic":"MACHINES :","question":"In the diagram below, XY represents a plank used to lift a load from a point X on the ground onto a horizontal platform YP. What is the velocity ratio of the plank?","images":["data:image/png;base64,"],"options":{"A":"XYZY","B":"XYXZ","C":"ZYXZ","D":"XZXY"},"answer":"A","explanation":"V.R=Distance moved by effortDistance moved by effort=XYZY","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>9","subject":"Physics","year":"1997","type":"Objective","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"A uniform bar 15 m long, is balanced on a pivot placed at its mid-point. A boy of mass 55 kg sits on one arm of the bar at a point 5 m away from the pivot. What mass can be placed at 2 m away from the end of the bar to keep the bar horizontal?","images":[],"options":{"A":"5.0 kg","B":"6.9 kg","C":"50.0 kg","D":"55.0 kg"},"answer":"C","explanation":"x  x 5.5 = 55 x 5   x =55 x 55.5=55 x 5055=50.0kg","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>10","subject":"Physics","year":"1997","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"A solid plastic cube of side 0.2 m is submerged in a liquid of density 0.8 kgm-3. Calculate the upthrust of the liquid on the cube.  [g = 10 ms-2]","images":[],"options":{"A":"0.064 N","B":"0.025 N","C":"0.016 N","D":"0.008 N"},"answer":"A","explanation":"Density = 0.8 kgm-3; g = 10 ms-2  Volume of cube = l3 = 0.2 x 0.2 x 0.2 = 8.0 x 10-3 m3  Upthrust = weight of liquid displaced = 8.0 x 10-3 x 0.8 x 10 = 0.064 N","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>11","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A piece of copper of mass 30 g loses 60 J of heat energy. If the specific heat capacity of iron is 400 Jkg-1K-1. Calculate the change in temperature of the copper.","images":[],"options":{"A":"0.2 K","B":"0.8 K","C":"2.0 K","D":"5.0 K"},"answer":"D","explanation":"m = 30 g = 0.03 kg; Q = 60 J; c = 400 Jkg-1K-1; \u03b8 = ?  Q = mc\u0394\u03b8; 60 = 0.03 x 400 x \u0394\u03b8  \u0394\u03b8=60400 x 0.03=604 x 3=6012=5.0K","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>12","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Steel bars, each of length 3 m at 28oC, are to be used for constructing a rail line. If the linear expansivity of steel is 1.0 x 10-3 K-1, what is the safety gap that must be left between successive bars if the highest temperature expected at 40oC?","images":[],"options":{"A":"1.2 x 10-1 cm","B":"7.2 x 10-2 cm","C":"6.0 x 10-2 cm","D":"3.6 x 10-2 cm"},"answer":"D","explanation":"\u03b1 = 1.0 x 10-5 K; L = 3 m = 300 cm; \u03b81 = 28oC; \u03b82 = 40oC; \u0394L = ?  \u03b1=\u0394LL\u0394\u03b8  \u0394L = \u03b1L\u0394\u03b8  \u0394L = 1.0 x 10-5 x 3 x (40 - 28) = 1.0 x 10-5 x 300 x 12 = 3.6 x 10-2 cm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>13","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Which of the following diagrams correctly represents the variation of the volume V of a fixed mass of water with temperature T?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"ThegraphobtainedfromvolumeVofafixedmassofwaterwithtemperatureTis  astraightlinewhoseslopeisapproximately1273","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>14","subject":"Physics","year":"1997","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"In which of the following digram is the pressure of the entrapped air equal to the atmospheric pressure?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"The pressure of the entrapped air equal to the atmospheric pressure when its rested horizontally.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>15","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A solid material of volume 100 cm3 is heated through a temperature difference of 40oC. Calculate the increase in the volume of the material if its linear expansivity is 2.0 x 10-6 K-1.","images":[],"options":{"A":"2.4 x 10-2 cm3","B":"1.6 x 10-2 cm3","C":"8.0 x 10-3 cm3","D":"5.0 x 10-6 cm3"},"answer":"A","explanation":"V=100cm3;\u03b8=40oC;\u03b1=2.0x10-6K-1;\u03b1=\u0394VV\u0394\u03b8  =3x2.0x10-6=\u0394V100 x 40  \u0394V=6.0x10-6x100x40=2.4x10-2cm3","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>16","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Which of the following explains why a thick glass cup cracks when boiling water is poured into it?","images":[],"options":{"A":"Large increase in the heat capacity of the cup","B":"High density of water","C":"Unequal expansion of the interior and exterior walls of the cup","D":"Anomalous expansion of water"},"answer":"C","explanation":"When hot water is poured into thick glass cup, the inner surface of the cup becomes hot and expands. The outer surface of the cup does not expand quickly. Due to this uneven expansion, the glass cup cracks.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>17","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"Calculate the quantity of heat released when 100 g of steam at 100oC condenses to water  [Take the specific latent heat of vaporization of water as 2.3 x 106 Jkg-1]","images":[],"options":{"A":"2.3 x 101 J","B":"2.3 x 102 J","C":"2.3 x 104 J","D":"2.3 x 105 J"},"answer":"D","explanation":"m = 100 g = 0.1 kg; \u03b8 = 100oC; L = 2.3 x 106 Jkg-1K-1; H = mL  \u2234 H = 0.1 x 2.3 x 106 = 2.3 x 105 J","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>18","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"A fixed mass of gas occupies a volume of 20 cm3 at a pressure of 700 mmHg. Assuming that the temperature remains constant, what will be the volume of the gas at 750 mmHg?","images":[],"options":{"A":"2.5 cm3","B":"15.5 cm3","C":"18.7 cm3","D":"21.4 cm3"},"answer":"C","explanation":"V1 = 20 cm3; P1 = 700 mmHg; V2 = ?; P2 = 750 mmHg  P1V1 = P2V2  V2=P1V1P2=700 x 20750=18.7cm3","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>19","subject":"Physics","year":"1997","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"A cup containing 100 g of pure water at 20oC is placed in a refrigerator. If the refrigerator extracts heat at the rate of 840 J per minute, calculate the time taken for the water to freeze.  [Neglect the heat capacity of the materials of the cup]  [Specific heat capacity of water = 4.2 Jg-1K-1]  [Specific latent heat of fusion of ice = 336 Jg-1]","images":[],"options":{"A":"15 minutes","B":"20 minutes","C":"42 minutes","D":"50 minutes"},"answer":"D","explanation":"m = 100 g; \u03b8 = 20oC; Q = 840 J; t = ?; Q = ml + mc\u0394\u03b8  Q = 100 x 336 + 100 x 4.2 x 20 = 33600 + 8400 = 42,000  Refrigerator absorbs 840 J per minutes  \u223442,000Jofheatwillbeabsorbedin42,000840minutes=50minutes","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>20","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"When white light is incident on a glass prism the spectrum produced on a screen placed beyond the prism is due to","images":[],"options":{"A":"diffraction","B":"reflection","C":"refraction","D":"polarization"},"answer":"C","explanation":"Dipersion is due to the fact that different colours of white light travel at different speeds through the glass. Each colour is therefore refracted in a slightly different direction or angle through the glass.  [N.B: In a vacuum and in air, all the colours of white light travel at the same speed.]","marks":"1","difficulty":"1"},{"id":"objective>Physics>1997>21","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"Two rays from a very distant object in the diagram below. P, F and C represents respectively the pole, focus and centre of curvature of a concave mirror. If two rays from a very distant object strike the mirror as shown, where will the image of the object be located?","images":["data:image/png;base64,"],"options":{"A":"Between P and F","B":"Between F and C","C":"Beyond C","D":"At F"},"answer":"D","explanation":"The image of the object be located at F.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>22","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A converging lens of focal length 15 cm is used to obtain a real image magnified 11/2 times. Calculate the distance of the image from the lens.","images":[],"options":{"A":"37.5 cm","B":"22.5 cm","C":"15.0 cm","D":"7.5 cm"},"answer":"A","explanation":"f=15cm;u=x;v=3x2;ifu=2x;v=3x  \u22341f=1v+1u  =115=13x+12x  =115=2 + 36x  =115=56x  =6x=15x5=75  \u2234x=756=12.5cm  v=3x=3x12.5=37.5cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>23","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"At what distance from a simple microscope must an object be placed so that an image 5 times the size of the object is produced 20 cm from the lens?","images":[],"options":{"A":"2.0 cm","B":"3.3 cm","C":"4.0 cm","D":"5.0 cm"},"answer":"C","explanation":"M=5i.evu=5\u2234v=5u=20cm(given);  \u2234u=205=4.0cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>24","subject":"Physics","year":"1997","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"What is the frequency of a radio wave of wavelength 150 m if the velocity of radio waves in free space is 3 x 108 ms-1?","images":[],"options":{"A":"4.5 x 1010 Hz","B":"5.0 x 109 Hz","C":"4.5 x 108 Hz","D":"2.0 x 106 Hz"},"answer":"D","explanation":"f = ?; v = 3 x 108 ms-1; \u03bb = 150 m; v = f\u03bb  f=v\u03bb=3 x 108150=2.0x106Hz","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>25","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"Whenever light waves are restricted to a specific plane, they are said to be","images":[],"options":{"A":"diffracted","B":"refracted","C":"diffused","D":"plane-polarized"},"answer":"D","explanation":"Plane polarized light consists of waves in which the direction of vibration is the same for all waves.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>26","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The magnification produced with a converging lens is 5. If the object is a square wire gauze of side 2 cm, calculate the area of the image","images":[],"options":{"A":"100 cm2","B":"40 cm2","C":"20 cm2","D":"10 cm2"},"answer":"C","explanation":"M = 5; L = 2 cm; Area of the object = L2 = 2 x 2 = 4 cm2  M=vu=Area of imageArea of object=5  \u2234 Area of image = Area of object x 5 = 4 x 5 = 20 cm2","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>27","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"Which of the following is  not  true of the similarities between a camera and the human eye?","images":[],"options":{"A":"Both the camera and the eye have light-proof interiors","B":"Both camera and the eye, have light sensitive screens","C":"Inverted images are formed on the screen in both","D":"The distance between the lens and the screen is fixed in both"},"answer":"D","explanation":"The distance between the lens and the retina is fixed in the human eye. In camera the distance between the lens and the film can be varied.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>28","subject":"Physics","year":"1997","type":"Objective","topic":"PROPERTIES OF WAVES : DIFFRACTION","question":"The diagram below shows waves passing through a slit S. Which wave phenomenon is illustrated by the diagram?","images":["data:image/png;base64,"],"options":{"A":"Reflection","B":"Refraction","C":"Polarization","D":"Diffraction"},"answer":"D","explanation":"Diffraction is the bending of waves around obstacles, or the spreading of waves by passing them through an aperture, or opening.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1997>29","subject":"Physics","year":"1997","type":"Objective","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"A sound note is produced by a ringing bell and the echo of the note from a nearby wall is received 0.5 s later. If the frequency of the note is 400 Hz and its wavelength 1 m, calculate the distance between the bell and the wall.","images":[],"options":{"A":"400 m","B":"200 m","C":"125 m","D":"100 m"},"answer":"D","explanation":"f = 400 Hz; \u03bb = 1 m; t = 0.5 s; d = ?  v=f\u03bb=400x1=400ms-1;v=2dt  \u2234d=vt2=400 x 0.52=2002=100m","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>30","subject":"Physics","year":"1997","type":"Objective","topic":"PROPERTIES OF WAVES : SUPERPOSITION","question":"The diagram below represents the profile of transverse wave. Which of the following points are in phase?","images":["data:image/png;base64,"],"options":{"A":"O and P","B":"O and Q","C":"O and R","D":"O and S"},"answer":"D","explanation":"If the crests of two waves pass the same point or line at the same time, then they are in phase for that position. Therefore (O and S) and also (P and T) are in phase","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>31","subject":"Physics","year":"1997","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The diagram below illustrates the profile of a progressive wave in which energy is transferred from P to Q in 3.0 x 10-3 s. Calculate the frequency of the wave.","images":["data:image/png;base64,"],"options":{"A":"2.0 x 103 Hz","B":"1.3 x 103 Hz","C":"1.0 x 103 Hz","D":"6.7 x 102 Hz"},"answer":"C","explanation":"Time for completing cycles in PQ = 3 x 10-3 s; t = ?  since we have three complete cycles in PQ \u2234 time to complete 3 cycles = 3 x 10-3 s  \u2234Timetocomplete1cycle(T)=3 x 10-33=1x10-3s  \u2234f=1T=11 x 10-3=1.0x103Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>32","subject":"Physics","year":"1997","type":"Objective","topic":"PROPERTIES OF WAVES : INTERFERENCE","question":"Two identical waves travelling in the same direction are superimposed, what should be the phase difference between the waves for maximum destructive interference to occur?","images":[],"options":{"A":"20o","B":"45o","C":"180o","D":"225o"},"answer":"C","explanation":"Destructive interference occurs from the superposition of two identical waves that are 180\u00b0(\u03c0 radians) out of phase.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>33","subject":"Physics","year":"1997","type":"Objective","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"A pipe, open at both ends, produces a fundamental note. If the velocity of sound in air is V and L the length of the pipe, which of the following expresses the frequency of the note?  [Neglect end correction]","images":[],"options":{"A":"2VL","B":"V2L","C":"V3L","D":"V4L"},"answer":"B","explanation":"L=\u03bb2\u2234\u03bb=2L;V=f\u03bb;f=V\u03bb=V2L","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>34","subject":"Physics","year":"1997","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"Which of the following statements is  not  correct?","images":[],"options":{"A":"The pitch of a note depends on the frequency of the vibrating source","B":"The loudness of a note depends on its intensity","C":"The velocity of sound in air does not depend on the intensity of the note producing it","D":"Wind speed has no effect on the speed of sound in air"},"answer":"D","explanation":"The wind can slow down or accelerate the speed of sound, depending on whether it is blowing in the same direction or in the opposite direction to the sound signal. For short distances, the wind has no other significant effects on the level of its receipt.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>35","subject":"Physics","year":"1997","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM","question":"A progressive wave has a wavelength of 50 cm. Calculate the phase difference between two points at a distance of 20 cm apart","images":[],"options":{"A":"103\u03c0","B":"52\u03c0","C":"45\u03c0","D":"23\u03c0"},"answer":"C","explanation":"\u03bb=50cm;\u0394x=20cmapart;  Phasedifference=2\u03c0\u03bbxpathdifference  \u0394\u03d5=2\u03c0\u03bbx\u0394x  \u0394\u03d5=2\u03c050x20=45\u03c0","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>36","subject":"Physics","year":"1997","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"An alternating current with a peak value of 5 A passes through a resistor of resistance 10.0 \u03a9. Calculate the rate at which energy is dissipated in the resistor.","images":[],"options":{"A":"250.0 W","B":"125.0 W","C":"50.0 W","D":"35.4 W"},"answer":"B","explanation":"Irms=Io&radic;2&nbsp;=5&radic;2&nbsp;  P=Irms2R=(5&radic;2&nbsp;)2x10=252x10=125.0W","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>37","subject":"Physics","year":"1997","type":"Objective","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"The invisible part of the spectrum of white light consists of the following colours:","images":[],"options":{"A":"red, orange and yellow only","B":"infra-red, ultra-violet and blue only","C":"indigo and green only","D":"ultra-violent and infra-red only"},"answer":"D","explanation":"Light, by definition, is the band of radiation to which our eye is sensitive. Ultraviolet radiation ( UV ) and infrared radiation (IR) are not visible. They are the bands of radiation on either side of the visible band (ultra means beyond, infra means below).","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>38","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"A charge of 1.0 x 10-5 C experiences a force of 40 N at a certain point in space. What is the magnitude of the electric field intensity at the point in newton per coulomb?","images":[],"options":{"A":"8.0 x 106","B":"4.0 x 106","C":"3.0 x 10-4","D":"2.0 x 10-4"},"answer":"B","explanation":"E=Fq=401.0 x 10-5=4.0x106","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>39","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An atom radiates 1.5 x 10-19 J of energy when an electron jumps from one energy level to another. What is the wavelength of the emitted radiation?  [Planck's constant = 6.6 x 10-34 Js, Speed of light in air = 3 x 108]","images":[],"options":{"A":"1.32 x 106 m","B":"2.98 x 10-6 m","C":"3.32 x 106 m","D":"6.82 x 10-6 m"},"answer":"A","explanation":"E=hf=hc\u03bb  \u03bb=hcE=6.6 x 10-34 x 3 x 1081.5 x 10-19=19.8 x 10-261.5 x 10-19=13.2x10-7m=1.32x10-6m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>40","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A capacitor of capacitance 25\u03bcf is connected to an a.c. power source of frequency 200/\u03c0 Hz.  Calculate the reactance of the capacitor.","images":[],"options":{"A":"0.01 \u03a9","B":"0.02 \u03a9","C":"50.00 \u03a9","D":"100.00 \u03a9"},"answer":"D","explanation":"XC=12\u03c0fC=12 x \u03c0 x 200/\u03c0 x 25 x 10-6=106104=100.00\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>41","subject":"Physics","year":"1997","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"The current in a series R-L-C circuit attain its maximum value when the","images":[],"options":{"A":"impedance is greater than the capacitive reactance","B":"inductive reactance is equal to the capacitive reactance","C":"inductive reactance is greater than the resistance","D":"capacitive reactance is less than the resistance"},"answer":"B","explanation":"WhenXL=XCi.e2\u03c0fL=12\u03c0fC  \u2234AtanRLCcircuit'sresonantfrequency,fo=12\u03c0\u221aLC,thecurrentamplitudeisatits  maximumvalue.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>42","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"In a photocell, light energy is converted to","images":[],"options":{"A":"electrical energy","B":"chemical energy","C":"heat energy","D":"mechanical energy"},"answer":"A","explanation":"In a photocell, light energy is converted into electrical energy. This is based on the photoelectric effect, where photons (light energy) strike the surface of a metal and cause electrons to be emitted. These emitted electrons create a current, which is electrical energy.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>43","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"When a resistor of resistance R is connected across a cell. The terminal p.d. of the cell is reduced to three-quarters of its e.m.f. The internal resistance of the cell is expressed as","images":[],"options":{"A":"R4","B":"R3","C":"R2","D":"3R4"},"answer":"B","explanation":"V = 3/4E (given); E = V + v = IR + Ir    SinceV=IR;I=VR=3/4ER  \u2234E=3/4E+3/4ERxr  E = 3/4E(1 + r/R)    1 = 3/4(1 + r/R)    Divide both sides by 3/4    4/3 = 1 + r/R    4/3 - 1 = r/R    1/3 = r/R    R = 3r  \u2234r=R3","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>44","subject":"Physics","year":"1997","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"A magnet is placed successively near rings made of the materials indicated in the diagrams below. The polarity of the magnet in each case is also indicated. Inside which of the rings will a magnetic field be observed?","images":["data:image/png;base64,"],"options":{"A":"I only","B":"III only","C":"I and III only","D":"II and III only"},"answer":"A","explanation":"The materials which are strongly attracted by a magnetic field or magnet is known as ferromagnetic material for eg:  iron ,  steel , nickel, cobalt etc. The  permeability  off these materials is very very high ( ranging up to several hundred or thousand).    [Magnetic  permeability  is a diagnostic physical property which characterizes the degree of induced magnetism a material experiences under the influence of an external magnetic field]","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>45","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Calculate the terminal potential difference across a 20 \u03a9 resistor connected to a battery of e.m.f. 15 V and internal resistance 5 \u03a9.","images":[],"options":{"A":"60.0 V","B":"15.0 V","C":"12.0 V","D":"6.3 V"},"answer":"C","explanation":"P.d = ?; R = 20 \u03a9; r = 5 \u03a9; E = 15 V  E=I(R+r)==>I=ER + r=1520 + 5=1525=0.6A  P.d (V) = IR = 0.6 x 20 = 12.0 V","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>46","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"A magnet is being inserted into a coil of wire. On which of the following factors does the induced e.m.f. in the coil depend on?  I. Numbers of turn in the circuit  II. Strength of the magnet  III. Speed with which the magnet is inserted into the coil.","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I, II and III"},"answer":"D","explanation":"Induced e.m.f for a coil of wire depends on four things:    Magnetic strength of the core in the coil of wire. (stronger --> bigger emf)  Number of turns of wire in the coil (more turns --> bigger emf)  The cross-sectional area of the coil (larger area --> bigger emf)  How fast you move the magnet into/out of the coil.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>47","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"During the electrolysis of copper(II) tetraoxosulphate(VI) solution, an ammeter shows a steady current reading of 1.0 A for 30 minutes while   6.6 x 10-4 kg of copper is liberated. Calculate the error in the ammeter reading.  [The electrochemical equivalent of copper is 3.30 x 10 kgC-1]","images":[],"options":{"A":"0.001 A","B":"0.011 A","C":"0.111 A","D":"1.000 A"},"answer":"C","explanation":"m = Zit; Z = 3.30 x 10-7 kgC-1; m = 6.6 x 10-4 kg; t = 30 minutes = 30 x 60 = 1800 s  \u2234I=mZt=6.6 x 10-43.30 x 10-7 x 1800=1.111  \u2234 Error in ammeter reading = 1.111 - 1 = 0.111 A","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>48","subject":"Physics","year":"1997","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"The relationship between the directions of the magnetic field, the current and the motion of a current-carrying wire in the field is easily remembered using","images":[],"options":{"A":"octet rule","B":"right-hand grip rule","C":"Maxwell screw rule","D":"Fleming left-hand rule"},"answer":"D","explanation":"John Ambrose Fleming introduced two rules to determine the direction of motion (in motors) or the direction of induced current (in generators). The rules are called as Fleming's left hand rule (for motors) and Fleming's right hand rule (for generators).     Fleming's Left-Hand Rule   \"If the forefinger points in the direction of magnetic field, the middle finger point in the direction of current, then the thumb will point in the direction of the force (motion)\".","marks":"1","difficulty":"1"},{"id":"objective>Physics>1997>49","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The current in the primary coil of a transformer is 2.5 A. If the coil has 50 turns and the secondary 250 turns, calculate the current in the secondary coil.  [Neglect energy loses in the transformer]","images":[],"options":{"A":"0.2 A","B":"0.5 A","C":"2.5 A","D":"5.0 A"},"answer":"B","explanation":"IP=2.5A;nS=250turns;nP=50turns;IS=?  ISIP=nPnS  \u2234IS=IP nPnS=2.5 x 50250=2.550=0.5A","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>50","subject":"Physics","year":"1997","type":"Objective","topic":"ELECTROMAGNETIC FIELD : LENZ\u2019S LAW","question":"Lenz's law of electromagnetic induction is essentially a statement of the","images":[],"options":{"A":"inverse-square law of gravitation","B":"inverse-square law of magnetism","C":"inverse-square law of electrostatics","D":"law of conservation of energy"},"answer":"D","explanation":"Lenz's law is based upon the law of conservation of energy. This law states that the induced current always tends to oppose the cause which produces it. So in order to do work against opposing forces, we have to put extra effort. This extra work leads to periodic changes in magnetic flux hence more current is induced.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>51","subject":"Physics","year":"1997","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"The odour of a leaking gas is perceived at a distance from the source. This is made possible by the process of","images":[],"options":{"A":"sublimation","B":"diffusion","C":"osmosis","D":"evaporation"},"answer":"B","explanation":"Diffusion is the process resulting from random motion of molecules by which there is a net flow of matter from a region of high concentration to a region of low concentration. A familiar example is the perfume of a flower that quickly permeates the still air of a room.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1997>52","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The half-life of a radioactive material is 6 hours. What quantity of 1 kg of the material would decay in 24 hours?","images":[],"options":{"A":"1516kg","B":"12kg","C":"14kg","D":"18kg"},"answer":"A","explanation":"half life = 6 hours; 24 hours = 4 half lives = 4 x 6 hours    Amountremainingafter4halflives=124of1kg=116of1kg=116kg  \u2234Quantitythatwoulddecayin24hours=1-116=1516kg  [OR]    \u2234 1 kg would decay to 1/2 kg after first half life (1/2 x 1.0 kg = 1/2 kg)    ==>  1/2 kg would decay to 1/4 kg after second half life (1/2 x 1/2 kg = 1/4 kg)    ==> 1/4 kg would decay to 1/8 kg after third half life (1/2 x 1/4 kg = 1/8 kg)    Finally 1/8 kg would decay to 1/16 kg after fourth half life (1/2 x 1/8 kg = 1/16 kg)    116kgwouldbeleft (or remains)after4halflives  \u2234Quantitythatwoulddecayin24hours=1-116=1516kg","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>53","subject":"Physics","year":"1997","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"When a paint brush is removed from clean water, the bristles of the brush are pulled together because of","images":[],"options":{"A":"the viscosity of the sorrounding air","B":"the low density of water","C":"surface tension forces","D":"the weight of the brush bristles"},"answer":"C","explanation":"When the brush is taken out of water, the bristles cling together due to surface tension. This happens because the free surface of water tries to acquire a minimum surface area (in order to reduce residual force) thus creating tension and that this tension is known as surface tension.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>54","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"Which of the following is a pair of isotopes?","images":[],"options":{"A":"35 18 Ar and 35 16 S","B":"35 17 Cl and 37 17 Cl","C":"15 7 N and 16 8 O","D":"30 14 Si and 30 15 P"},"answer":"B","explanation":"Isotopes are members of a family of an element that all have the same number of protons but different numbers of neutrons. The number of protons in a nucleus determines the element's atomic number on the Periodic Table. For example, chlorine has 17 protons and is atomic number 17.    Chlorine has two stable isotopes, 35Cl (75.77%) and 37Cl (24.23%), giving chlorine a standard atomic weight of 35.45.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>55","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Which of the following statements is not true of nuclear fission?","images":[],"options":{"A":"A mother nucleus is broken into two daughter nuclei roughly of equal parts","B":"Neutron is normally used in bombarding heavy nucleus","C":"Two light nuclei are made to combine to form a heavy nucleus","D":"Very enormous energy is released"},"answer":"C","explanation":"Nuclear fission is a reaction in which the nucleus of an atom splits into two or more smaller nuclei. The fission process often produces gamma photons, and releases a very large amount of energy.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>56","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A nucleus has a proton number of 84. it emits an \u03b1 - particle and then a \u03b2 - particle to achieve stability. What is the proton number of the product?","images":[],"options":{"A":"81","B":"82","C":"83","D":"86"},"answer":"C","explanation":"84A --> 82A1 + 42\u03b1     82A1 --> 83A2 + 0-1\u03b2;","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>57","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"In a nuclear reaction, the mass defect is 2.0 x 10-6 g. Calculate the energy released, given that the velocity of light is 3.0 x 108 ms-1.","images":[],"options":{"A":"9.0 x 107 J","B":"1.8 x 108 J","C":"1.8 x 109 J","D":"9.0 x 1010 J"},"answer":"B","explanation":"E = ? \u0394m = 2.0 x 10-6 g = 2.0 x 10-9 kg; c = 3 x 108 ms-1  E = \u0394mc2 =  2.0 x 10-9 x (3 x 108)2 = 2.0 x 10-9 x 9 x 1016 = 18 x 107 J = 1.8 x 108 J","marks":"1","difficulty":"3"},{"id":"objective>Physics>1997>58","subject":"Physics","year":"1997","type":"Objective","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"The ratio of tensile stress to tensile strain is known as","images":[],"options":{"A":"modulus of rigidity","B":"modulus of elasticity","C":"shear modulus","D":"Young modulus"},"answer":"D","explanation":"The Young's modulus (E) is a property of the material that tells us how easily it can stretch and deform and is defined as the ratio of tensile stress (\u03c3) to tensile strain (\u03b5). Where stress is the amount of force applied per unit area (\u03c3 = F/A) and strain is extension per unit length (\u03b5 = dl/l).","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>59","subject":"Physics","year":"1997","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Which of the following is  not  correct about Rutherford's model of the atom?","images":[],"options":{"A":"The mass of an atom is concentrated in the nucleus","B":"The nucleus of an atom is positively charged","C":"The nucleus is sorrounded by electron cloud","D":"The model is applicable to atoms with only one electron in the outer shell"},"answer":"D","explanation":"The model described the atom as a tiny, dense, positively charged core called a nucleus, in which nearly all the mass is concentrated, around which the light, negative constituents, called electrons, circulate at some distance, much like planets revolving around the Sun.    [Rutherford's experiments suggested that the size of the nucleus is about 10-14 m to 10-15 m]","marks":"1","difficulty":"2"},{"id":"objective>Physics>1997>60","subject":"Physics","year":"1997","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following statements about kinetic theory of matter is  not  correct?","images":[],"options":{"A":"The molecules of matter are always in motion","B":"When a body is heated, the average kinetic energy of its molecules decreases","C":"Molecules of a liquid move more freely than those of a solid","D":"Matter is made up of many tiny particles called molecules"},"answer":"B","explanation":"The kinetic theory of matter states that all matter is made of small particles that are in random motion and that have space between them.    Therefore when a body is heated, the average kinetic energy of its molecules increases","marks":"1","difficulty":"2"}];